// // This module implements an EEPROM cell that supports Write, Read, and Erase operations. Writing a 1-bit value to the cell is achieved by setting the write_en signal high and providing the desired data_in. Reading the stored value can be done by asserting the read_en signal. The erase_en signal resets the cell to 0.
module eeprom_cell (
    input wire clk,
    input wire write_en,
    input wire read_en,
    input wire erase_en,
    input wire data_in,
    output reg data_out
);

    always @(posedge clk) begin
        if (erase_en) begin
            data_out <= 1'b0;
        end else if (write_en) begin
            data_out <= data_in;
        end else if (read_en) begin
            // data_out is updated on read; no action needed here
        end
    end
endmodule
